# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency. Follow security best practices.
# Category: race_condition

public async Task<bool> PurchaseTicketsAsync(int eventId, int userId, int quantity)
{
    using (var context = new EventBookingContext())
    {
        using (var transaction = await context.Database.BeginTransactionAsync())
        {
            try
            {
                var eventEntity = await context.Events
                    .Include(e => e.Seats)
                    .FirstOrDefaultAsync(e => e.Id == eventId);

                if (eventEntity == null || quantity <= 0)
                {
                    return false; // Event not found or invalid quantity
                }

                var availableSeats = eventEntity.Seats.Count(s => s.IsAvailable);
                if (availableSeats < quantity)
                {
                    return false; // Not enough available seats
                }

                var seatsToPurchase = eventEntity.Seats
                    .Where(s => s.IsAvailable)
                    .OrderBy(s => s.SeatNumber)
                    .Take(quantity)
                    .ToList();

                foreach (var seat in seatsToPurchase)
                {
                    seat.IsAvailable = false; // Mark seat as purchased
                }

                var purchase = new TicketPurchase
                {
                    EventId = eventId,
                    UserId = userId,
                    Quantity = quantity,
                    PurchaseDate = DateTime.UtcNow
                };

                context.TicketPurchases.Add(purchase);
                await context.SaveChangesAsync();

                await transaction.CommitAsync();
                return true;
            }
            catch (DbUpdateConcurrencyException)
            {
                await transaction.RollbackAsync();
                return false; // Handle concurrency conflict
            }
            catch (Exception)
            {
                await transaction.RollbackAsync();
                throw; // Rethrow unexpected exceptions
            }
        }
    }
}